/* 监听页面显示隐藏 */
function onPageVisibility(functions){
    var _t = {};
    var onShowCall = function(){
        if(!functions || !functions.show){
            return;
        }
        window.clearTimeout(_t.showTime);
        _t.showTime = window.setTimeout(function(){
            functions.show();
        },100);
    }
    var onHideCall = function(){
        if(!functions || !functions.hide){
            return;
        }
        window.clearTimeout(_t.hideTime);
        _t.hideTime = window.setTimeout(function(){
            functions.hide();
        },100);
    }
    document.addEventListener('visibilitychange', function(){
        var visibility = document.visibilityState;
        if(visibility == 'visible'){
            onShowCall();
        }else if(visibility == 'hidden'){
            onHideCall();
        }
    });

    window.addEventListener("pageshow", function(){
        onShowCall()
    }, false);

    window.addEventListener("pagehide", function(){
        onHideCall();
    }, false);
}

var showPhoneOrEmail = '';
var otpCodeValid = true;

function checkUserPhone() {
    const hasPhone = $("#changePhone_otp").val();
    const hasEmail = $("#emailValid_otp").val();
    showPhoneOrEmail="phone";
    // 1. 手机号、邮箱都没有展示没有校验方式提示
    if(!hasPhone && !hasEmail) {
        $("#otpNoAuthDialog").show();
        return;
    } else if(hasPhone!="" && hasEmail!=""){
        //2. 用户拥有手机号和邮箱展示切换radio
        // 2.1 手机号存在
        $("#validPhoneBox").show();
        $("#validEmailBox").hide();
        $("#phoneRadio .common-radio-inner").addClass("common-radio-checked");
        $("#emailRadio .common-radio-inner").removeClass("common-radio-checked");
    }else if(hasPhone!="" && hasEmail==""){
        // 2.2 手机号存在,邮箱不存在
        $("#validPhoneBox").show();
        $("#otpValidRadioGroup").hide();
        $("#validEmailBox").hide();
        $("#phoneRadio .common-radio-inner").addClass("common-radio-checked");
        $("#emailRadio .common-radio-inner").removeClass("common-radio-checked");
    }else if(hasPhone=="" && hasEmail!=""){
        showPhoneOrEmail="email";
        // 2.3 手机号不存在,邮箱存在
        $("#validPhoneBox").hide();
        $("#otpValidRadioGroup").hide();
        $("#validEmailBox").show();
        $("#phoneRadio .common-radio-inner").removeClass("common-radio-checked");
        $("#emailRadio .common-radio-inner").addClass("common-radio-checked");
    }
    countDownButton($("#getImprovePhoneCodeId_otp"), 0);
    countDownButton($("#getImproveEmailCodeId_otp"), 0);
    //清空验证码和提示
    clearReAuthOtpMsg();
    $("#otpCheckPhoneModal").modal("toggle");
    $(".modal-backdrop").css("background-color","rgb(0 0 0 / 20%)");
}

// otpRadio切换
function handleChangeRadio(val) {
    showPhoneOrEmail = val.querySelector('input[type="radio"]').value;
    const curInEle = val.querySelector('.common-radio-inner');  
    curInEle.classList.add('common-radio-checked');
    const ohterId = showPhoneOrEmail === "phone" ? "emailRadio" : "phoneRadio";
    const other = document.getElementById(ohterId); 
    other.querySelector('.common-radio-inner').classList.remove('common-radio-checked');
    if(showPhoneOrEmail === "email") {
        $("#validPhoneBox").hide();
        $("#validEmailBox").show();
    } else {
        $("#validPhoneBox").show();
        $("#validEmailBox").hide();
    }
    clearReAuthOtpMsg();
}

//清空验证码等提示
function clearReAuthOtpMsg() {
    $("#checkPhoneCode_otp").removeClass("common-input-error");
    $("#checkEmailCode_otp").removeClass("common-input-error");
    $("#checkReAuthOtpMsg").text("");
    $("#checkPhoneCode_otp").val("");
    $("#checkEmailCode_otp").val("");
}

// 失焦校验
function handleBlurValidCode(event) {
    otpCodeValid = event.target.value ? true : false;
    if(otpCodeValid) {
        event.srcElement.classList.remove("common-input-error");
        $("#checkReAuthOtpMsg").text('');
    } else {
        event.srcElement.classList.add("common-input-error");
        $("#checkReAuthOtpMsg").text(reAuthParams.dynamicEmpty);
    }
}

