//校验验证码.
function checkReAuthOtpPhoneCode(that) {
    $("#checkReAuthOtpMsg").text('');
    var checkPhoneCode = '';
    if(showPhoneOrEmail=="email"){
        checkPhoneCode = $("#checkEmailCode_otp").val();
        if(!checkRequired($("#checkEmailCode_otp"), reAuthParams.dynamicEmpty)){
            $("#checkReAuthOtpMsg").text(reAuthParams.dynamicEmpty);
            return;
        }
    }else{
        checkPhoneCode = $("#checkPhoneCode_otp").val();
        if(!checkRequired($("#checkPhoneCode_otp"), reAuthParams.dynamicEmpty)){
            $("#checkReAuthOtpMsg").text(reAuthParams.dynamicEmpty);
            return;
        }
    }
    disabledBtn($(that), true);
    $.ajax({
        type: "POST",
        url: contextPath+"/otp/checkDynamicCodeByReAuthOtp.do",
        dataType: "json",
        data: {
            checkPhoneCode:checkPhoneCode,showPhoneOrEmail:showPhoneOrEmail
        },
        success: function (data) {
            if(data.errCode == 1){
           		//手机号校验成功，展示otp绑定二维码
                $.ajax({
                    type: "POST",
                    url: contextPath+"/otp/getOtpToken.do",
                    dataType: "json",
                    data: {
                        otpSign:data.data,
                    },
                    success: function (data) {
                        if(data.code == 1){
                            //展示otp绑定二维码
                            $("#otpCheckPhoneDialog").hide();
                            $("#otpCheckUserPhone").hide();
                            $("#reAuthOtpDec").html(reAuthParams.reAuthOtpDec2);
                            //弹出层遮罩
                            $(".show").hide();
                            //otp绑定
                            $("#otpBindDiv").show();
                            $("#otpCheckPhoneModal").hide();
                            $("#otpBindImg").attr("src","data:image/jpeg;base64,"+data.data.otpUrl);
                            clearOtpCode();
                        }else{
                            $("#checkReAuthOtpMsg").text(utils.subStr(data.message, 40));
                        }
                        disabledBtn($(that), false);
                    }
                });
            }else{
                $("#checkReAuthOtpMsg").text(utils.subStr(data.errMsg, 40));
            }
            disabledBtn($(that), false);
        }
    });
}

