//统一校验必填和展示错误信息的方法
function checkRequired(that, errorMsg) {
	if($(that).val().trim() == ''){
		$(that).addClass("required");
		$(that).parent().parent().find(".reauth_error").empty().html(errorMsg);
		return false;
	}
	return true;
}


