//动态码发送后倒计时函数
var timeFlag;
function countDownButton(obj, second) {
	// 如果秒数还是大于0，则表示倒计时还没结束
    if (second > 0) {
    	$(obj).attr("disabled",true)// 按钮置为不可点击状态
        $(obj).addClass("send-code-disabled");
    	$(obj).text(second + "s");// 按钮里的内容呈现倒计时状态
        second--;// 时间减一
        timeFlag = setTimeout(function() {
        	countDownButton(obj, second);
    	}, 1000);
    } else {
    	// 否则，按钮重置为初始状态
    	$(obj).attr("disabled",false)// 按钮置未可点击状态
        $(obj).removeClass("send-code-disabled");
        $(obj).text(reAuthParams.getCodeName);// 按钮里的内容恢复初始状态
        //处理信息过长
        utils.showMsg($(obj), $(obj).text(),null,5);
        clearTimeout(timeFlag);//停止定时任务
    }
}

