function sendDynamicCodeByPhone(that) {
	if(reAuthParams.reAuthType == '3'){
		authCodeTypeName = "reAuthDynamicCodeType";
	}else if(reAuthParams.reAuthType == '4'){
		authCodeTypeName = "reAuthWChatDynamicCodeType";
	}else if(reAuthParams.reAuthType == '5'){
		authCodeTypeName = "reAuthCpdailyDynamicCodeType";
	}else if(reAuthParams.reAuthType == '11'){
        authCodeTypeName = "reAuthEmailDynamicCodeType";
    }else if(reAuthParams.reAuthType == '12'){
        authCodeTypeName = "reAuthDingTalkDynamicCodeType";
    }else if(reAuthParams.reAuthType == '13'){
        authCodeTypeName = "reAuthWeLinkDynamicCodeType";
    }
    $(".reauth_error").empty();
	disabledBtn($(that), true);
    $.ajax({
        type: "POST",
        url: contextPath+"/dynamicCode/getDynamicCodeByReauth.do",
        dataType: "json",
        data: {userName: reAuthParams.reAuthUserId, authCodeTypeName: authCodeTypeName},
        success: function (data) {
            var returnMessage = data.returnMessage;
            disabledBtn($(that), false);
            if (data.res == "success") {
                if(data.mobile !=undefined){
                    returnMessage = returnMessage + data.mobile;
                }
                $(".reauth_error_submit").html("<span style='color:#efa30e'>"+returnMessage+"<span>");
            	countDownButton($("#getDynamicCode"), data.codeTime);
            } else if (data.res == "wechat_success") {
                countDownButton($("#getDynamicCode"), 120);
            } else if (data.res == "cpdaily_success") {
                countDownButton($("#getDynamicCode"), 120);
            }else if(data.res == "code_time_fail"){
                $(".reauth_error_submit").html("<span style='color:red'>"+returnMessage+"<span>");
            	countDownButton($("#getDynamicCode"), data.codeTime);
            }else{
                $(".reauth_error_submit").html("<span style='color:red'>"+returnMessage+"<span>");
            }
        }
    });
}

function changeReAuthType(that){
    var reAuthType=$(that).attr("id");
    $.ajax({
        type: "POST",
        url: contextPath+"/reAuthCheck/changeReAuthType.do",
        dataType: "json",
        data: {isMultifactor: reAuthParams.isMultifactor,reAuthType:reAuthType,service:reAuthParams.service},
        success: function (data) {
            $("*").removeClass("required");
            $(".reauth_error").empty();
            $(".reauth_error_submit").empty();
            if(data.code==1){
                reAuthParams.reAuthType = data.data.reAuthType;
                if(data.data.reAuthType == '6' || data.data.reAuthType == '18'
                    || data.data.reAuthType.indexOf("real_person_plugin_") !== -1 || data.data.reAuthType.indexOf("REAL_PERSON_PLUGIN_") !== -1){
                    $("#changeReAuthTypeButton").find(".drop_ellipsis").text(reAuthParams.faceAuthName);
                    $("#reAuthTypeNameDesc").val(data.data.reAuthTypeNameDesc);
                }else{
                    $("#changeReAuthTypeButton").find(".drop_ellipsis").text(data.data.reAuthTypeName);
                }
                if(data.data.reAuthUserNameInput) {
                    $("#username").val(data.data.reAuthUserNameInput);
                    $('#username').attr('title', data.data.reAuthUserNameInput);
                }
                $(".changeReAuthTypes").show();
                $("#"+reAuthParams.reAuthType).hide();
                //如果是otp 初始化配置
                if(reAuthParams.reAuthType=="10"){
                    $("#clockTime").html(data.data.systemTime);
                    $("#countryCode_otp_option").text(data.data.userPhonePre);
                    $("#changePhone_otp").val(data.data.userPhone);
                    $("#emailValid_otp").val(data.data.userSecurityEmail);
                    $("#reAuthOtpDec").html(reAuthParams.reAuthOtpDec1);
                    $("#reAuthOtpDec").html(reAuthParams.reAuthOtpDec2);
                }
                initView();
                if(reAuthParams.reAuthType=="10" && data.data.otpIsBind==false){
                    //展示otp绑定二维码
                    $("#reAuthOtpDec").html(reAuthParams.reAuthOtpDec2);
                    $("#otpBindDiv").show();
                    $("#otpBindImg").attr("src","data:image/jpeg;base64,"+data.data.otpUrl);
                }
            }else{
                $(".reauth_error_submit").html(data.message);
            }
        }
    });
}

function refreshType(){
	$.ajax({
        type: "POST",
        url: contextPath+"/reAuthCheck/refreshReAuthType.do",
        dataType: "json",
        data: {usedType: reAuthParams.reAuthType, isMultifactor: reAuthParams.isMultifactor,service:reAuthParams.service},
        success: function (data) {
        	$("*").removeClass("required");
        	$(".reauth_error").empty();
        	if(data.reAuthType){
        		reAuthParams.reAuthType = data.reAuthType
            	initView();
        	}else{
        		$(".reauth_error").html(requestTimeOut);
        	}
        }
    });
}

var btnColor = {};
function disabledBtn(that, flag){
	if(flag){
		$(that).attr("disabled",true).addClass("disabled_btn");
	}else{
		$(that).attr("disabled",false).removeClass("disabled_btn");
	}
}

// 设置plain样式按钮禁用
function commonDisabledBtn(that, flag){
	if(flag){
		$(that).attr("disabled",true).addClass("common-plain-primary-btn-disabled");
	}else{
		$(that).attr("disabled",false).removeClass("common-plain-primary-btn-disabled");
	}
}

function startTime() {
    try {
        var clockTime = $("#clockTime");
        if(clockTime && clockTime!='') {
            var systemTime = clockTime.html();
            var cacheTime = new Date(Date.parse(systemTime.replace(/-/g, "/")));
            var date = new Date(cacheTime.getTime() + 1000);
            var year = date.getFullYear(); //当前年份
            var month = date.getMonth(); //当前月份
            var data = date.getDate(); //天
            var hours = date.getHours(); //小时
            var minute = date.getMinutes(); //分
            var second = date.getSeconds(); //秒
            var time = year + "-" + checkTime((month + 1)) + "-" + checkTime(data) + " " + checkTime(hours) + ":" + checkTime(minute) + ":" + checkTime(second);
            clockTime.html(time);
        }
        setTimeout('startTime()', 1000); //每一秒中重新加载startTime()方法
    }catch (e){

    }
}
//补位 当某个字段不是两位数时补0
function checkTime(str) {
    var num;
    str >= 10 ? num = str : num = "0" + str;
    return num;
}


// 展示绑定指南弹窗
$(document).on('click', '.otp_reauth_bind_guide',function() {
    $(".bind-guide-modal").css("display", "block");
})

// 隐藏绑定指南弹窗
$(document).on('click', '.guide-close',function() {
    $(".bind-guide-modal").css("display", "none");
})

// 处理仅本次登录
$(document).on('click', '.trust-device-cancel-btn',function () {
    $(".trust-device-modal").css("display", "none");
    if(curLoginType === "login") {
        loginParams.skipTmpReAuth = false;
        handleDoLoginInterface(loginParams);
    } else {
        handleGoCombined(false);
    }
})

// 处理信任此设备
$(document).on('click', '.trust-device-sub-btn',function() {
    $(".trust-device-modal").css("display", "none");
    if(curLoginType === "login") {
        loginParams.skipTmpReAuth = true;
        handleDoLoginInterface(loginParams);
    } else {
        handleGoCombined(true);
    }
})



function refreshMFAQrCode() {
    getMFAQrCode($("#mfa_uuid").val());
    $("#mfa_qr_code").show();
    // $(".qrcode_img_tip").show();
    $("#mfa_qr_invalid").hide();
    $("#mfa_qr_success").hide();
    // window.location.reload();
}

function getMFAQrCode(uuid) {
	// if(!QR_LOGIN_ENABLED || QR_LOGIN_ENABLED!=1){
    // 	clearTimeout(qr_time);
    // 	return;
    // }
    $.ajax({
        url: contextPath + "/reAuthCheck/getToken?ts=" + new Date().getTime(),
        data: {"uuid": uuid},
        dataType: "json",
        success: function (data, textStatus) {
            if (data.errCode == "1") { // 请求成功
                var src = contextPath + "/reAuthCheck/getCode?uuid="+data.uuid;
                $("#mfa_qr_img").attr("src", src);
                $("#mfa_qr_img_invalid").attr("src", src);
                $("#mfa_uuid").val(data.uuid);
                countDownMFA();
            }else{
                utils.alertBox(data.errMsg);
            }
        }
    });
}

var mfa_qr_time;
function countDownMFA() {
    mfa_qr_time = setTimeout(function () {
        isMFAQrCodeUsed();
        countDownMFA();
    }, 1000);
}

//二维码状态
function isMFAQrCodeUsed() {
    $.ajax({
        url: contextPath + "/reAuthCheck/getStatus.htl?ts=" + new Date().getTime(),
        data: {"uuid": $("#mfa_uuid").val()},
        dataType: "text",
        timeout: 5000,
        error: function () {
            clearTimeout(mfa_qr_time);
        },
        success: function (data, textStatus) {
            if (textStatus == "success" && data == "1") { // 请求成功
                clearTimeout(mfa_qr_time);
                // $("#qrLoginForm").submit();
                $(".submit_btn").click();
            }
            if (textStatus == "success" && data == "2") { // 二维码已被扫描跳
                $("#mfa_qr_code").hide();
                $("#mfa_qr_invalid").hide();
                $("#mfa_qr_success").show();
                // $(".qrcode_img_tip").hide();
            }
            if (textStatus == "success" && data == "3") { // 二维码已失效页面
                clearTimeout(mfa_qr_time);
                $("#mfa_qr_code").hide();
                $("#mfa_qr_success").hide();
                $("#mfa_qr_invalid").show();
            }
        }
    });
}


//刷新
function refresh() {
    getQrCode();
    //window.location.reload();
    $("#qr_code").show();
    $("#qr_invalid").hide();
    $("#qr_success").hide();
}
//动态码发送后倒计时函数
var reFreshCode = "0";
// 返回二维码
function backQrCode() {
    $("#qr_success").hide();
    reFreshCode = "1";
}
//获取token
function getQrCode() {
    var pluginId = $("#pluginId").val();
    var uuid = $("#uuid").val();
    $.ajax({
        url: contextPath + "/faceAuthWithPlugins/getQrCodeById?ts=" + new Date().getTime(),
        data: {pluginId:pluginId, uuid: uuid},
        dataType: "json",
        success: function (data, textStatus) {
            if (data.errCode == "1") { // 请求成功
                var src = contextPath + "/faceAuthWithPlugins/getQrCodeByFace?pluginId="+pluginId+"&uuid="+data.uuid;
                $("#qr_img").attr("src", src);
                $("#uuid").val(data.uuid);
                countDown();
            }else{
                utils.alertBox(data.errMsg);
            }
        }
    });
}

var qr_time;
function countDown() {
	if($("#aliFaceDiv").css('display') != 'none' || $("#tencentFaceDiv").css('display') != 'none'){
		//防止页面加载时但认证方式不是人脸识别就一直刷新
		isUsed();
		qr_time = setTimeout(function () {
			countDown();    	
	    }, 1000);
	}else{
		clearTimeout(qr_time);
	}
}

//二维码状态
function isUsed() {
    var pluginId = $("#pluginId").val();
	var uuid = $("#uuid").val();
	if(uuid == ''){
		return;
	}
    $.ajax({
        url: contextPath + "/faceAuthWithPlugins/getStatus?ts=" + new Date().getTime(),
        data: {pluginId:pluginId, uuid: uuid},
        dataType: "json",
        timeout: 5000,
        error: function () {
        	clearInterval(qr_time);
        },
        success: function (data, textStatus) {
            if (data.state == "1") { // 请求成功
                clearInterval(qr_time);
                //$("#faceLoginForm").submit();
                $(".submit_btn").click();
            }
            if (data.state == "2" && reFreshCode == "0") { // 二维码已被扫描跳
                // $("#qr_code").hide();
                $("#qr_invalid").hide();
                $("#qr_success").show();
            }
            if (data.state == "3") { // 二维码已失效页面
                clearInterval(qr_time);
                // $("#qr_code").hide();
                $("#qr_success").hide();
                $("#qr_invalid").show();
            }
        }
    });
}
